import React from 'react';

const demo = [
  {id:1,time:'2024-12-20 10:12',user:'Jane Smith',action:'Approved loan #21'},
  {id:2,time:'2024-12-19 15:20',user:'Mike Johnson',action:'Recorded deposit for John Doe'},
  {id:3,time:'2024-12-18 09:03',user:'System',action:'User account created: emily@example.com'}
];

const AuditLogs = ()=>{
  return (
    <div>
      <h3>Audit Logs</h3>
      <div style={{marginTop:12}} className="card">
        <h4 style={{marginTop:0}}>Timeline</h4>
        <div style={{display:'grid',gap:8}}>
          {demo.map(d=> (
            <div key={d.id} style={{padding:10,background:'rgba(255,255,255,0.02)',borderRadius:8}}>
              <div style={{fontSize:13,color:'var(--muted)'}}>{d.time} — {d.user}</div>
              <div>{d.action}</div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}
export default AuditLogs;
